package cn.org.starpivot.api.fallback;import cn.org.starpivot.api.mall.cart.CartInternalClient;import org.springframework.cloud.openfeign.FallbackFactory;public class CartInternalClientFallbackFactory implements FallbackFactory<CartInternalClient> {    private static final String ACTION = "购物车服务";    @Override    public CartInternalClient create(Throwable cause) {        return memberId -> FeignFallbackSupport.unavailable(cause, ACTION);    }}